package com.cho2hand.marketplace.service.impl.notification; import com.cho2hand.marketplace.dto.notification.NotificationResponse; import com.cho2hand.marketplace.entity.notification.Notification; import com.cho2hand.marketplace.exception.UserAccessDeniedException; import com.cho2hand.marketplace.repository.notification.NotificationRepository; import com.cho2hand.marketplace.service.notification.NotificationService; import java.util.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional;
@Service @Transactional public class NotificationServiceImpl implements NotificationService{private final NotificationRepository notifications;public NotificationServiceImpl(NotificationRepository n){notifications=n;}public void create(Long recipient,String type,String body,String path){var n=new Notification();n.setRecipientUserId(recipient);n.setType(type);n.setBody(body);n.setReferencePath(path);notifications.save(n);} @Transactional(readOnly=true) public List<NotificationResponse> list(Long recipient){return notifications.findByRecipientUserIdOrderByCreatedAtDesc(recipient).stream().map(this::response).toList();}public void read(Long recipient,Long id){var n=notifications.findById(id).filter(v->recipient.equals(v.getRecipientUserId())).orElseThrow(UserAccessDeniedException::new);n.markRead();}private NotificationResponse response(Notification n){return new NotificationResponse(n.getId(),n.getType(),n.getBody(),n.getReferencePath(),n.getReadAt(),n.getCreatedAt());}}
